const a = msg.payload.alarm;

function parseDateTime(dateStr, timeStr) {
    if (!dateStr || !timeStr) return null;
    const [day, month, year] = dateStr.split("/").map(s => s.trim());
    const [hour, minute] = timeStr.trim().split(":");
    return `${"20" + year}-${month.padStart(2, "0")}-${day.padStart(2, "0")}T${hour}:${minute}:00`;
}

msg.payload = {
    ref: a.ref?.[0],
    store: a.storeName?.[0],
    unit: a.unitName?.[0],
    device: a.deviceName?.[0]?.trim(),
    name: a.name?.[0],
    status: a.status?.[0],
    action: a.action?.[0],
    severity: a.severity?.[0],
    setting: a.setting?.[0],
    occurred: parseDateTime(a.occurDate?.[0], a.occurTime?.[0]),
    cleared: parseDateTime(a.clearDate?.[0], a.clearTime?.[0]),
    acknowledged: parseDateTime(a.ackDate?.[0], a.ackTime?.[0]),
    ackUser: a.ackUserAcct?.[0],
    value: a.value?.[0]?._,
    parval: a.value?.[0]?.$?.parval,
    ip: msg.ip?.replace("::ffff:", "")
};

return msg;

const ref = msg.payload.ref
if (ref !== undefined && ref !== null) {
    msg.payload = `<ack ref="${ref}"/>`;

    return msg;
}

node.done();

var bridge = global.get("cloud.bridges").find(bridge => {
    return bridge.id === msg.payload.find(flow => flow.id === msg.thisflow).label;
})
bridge.image.metrics = {};
bridge.error = false;

flow.set("bridge", bridge);

return msg;

const functions = {
    "deviceState": (metricId, parameterIds) => {
        if (!flow.get("bridge.image.metrics").hasOwnProperty(metricId)) {
            msg.payload[metricId] = 0;
        }
        if (parameterIds.length === 0) {
            parameterIds = flow.get("bridge.image.protocols").filter(dataPoint => {
                return dataPoint.topic.includes("error")
            }).map(dataPoint => {
                return dataPoint.id;
            });
        }

        const ok = Object.keys(flow.get("bridge.image.metrics")).filter(key => {
            return parameterIds.includes(key)
        }).reduce((accumulator, id) => accumulator && (flow.get("bridge.image.metrics")[id] === "" || flow.get("bridge.image.metrics")[id] === 0 || flow.get("bridge.image.metrics")[id] === false), true)

        if (ok) {
            msg.payload[metricId] = 0;
        } else {
            msg.payload[metricId] = 2;
        }
    }
}

const executor = (metricId, func, parameterIds) => {
    msg.payload[metricId] = eval("(" + func + ")")(...parameterIds.map(x => flow.get("bridge.image.metrics")[x]))
}

msg.sequences.forEach(sequence => {
    msg = sequence;
    msg.payload = {};
    let calc = sequence.dataPoint.calculation
    let metricsExist = calc.ids.reduce((accumulator, currentValue) => accumulator && flow.get("bridge.image.metrics").hasOwnProperty(currentValue), true)
    if (metricsExist) {
        if (functions.hasOwnProperty(calc.func)){
            functions[calc.func](sequence.dataPoint.id, calc.ids)
        } else {
            executor(sequence.dataPoint.id, calc.func, calc.ids);
        }
    } else {
        throw "Parameter IDs: " + calc.ids + " is missing for calculation";
    }
    node.send(msg);
});

node.done();

msg.sequences = flow.get("bridge.image.virtuals").map(dataPoint => {
    return {
        dataPoint: dataPoint
    };
});

if (msg.sequences.length > 0) {
    node.send(msg);
}

node.done();

var cloudBridge = global.get("cloud.bridges").find(bridge => {
    return bridge.id === flow.get("bridge").id
})

msg.stateUpstreamRequired = false;
msg.errorUpstreamRequired = false;
for (var propertyName in msg.payload) {
    if (typeof msg.payload[propertyName] === "number") {
        // Round to 2 decimal
        msg.payload[propertyName] = Math.round((msg.payload[propertyName] + Number.EPSILON) * 100) / 100
    }
    if (msg.dataPoint.topic.find(topic => topic === "error") && flow.get("bridge").image.metrics[propertyName] !== undefined && flow.get("bridge").image.metrics[propertyName] !== msg.payload[propertyName]) {
            msg.errorUpstreamRequired = true;
    }
    if (msg.dataPoint.topic.find(topic => topic === "state") && flow.get("bridge").image.metrics[propertyName] !== undefined && flow.get("bridge").image.metrics[propertyName] !== msg.payload[propertyName]) {
        msg.stateUpstreamRequired = true;
    }
    flow.get("bridge").image.metrics[propertyName] = msg.payload[propertyName];
}

cloudBridge.image.metrics = flow.get("bridge").image.metrics;

return msg;

msg.payload = {
    "payload" : msg.payload,
    "error" : msg.error
};

if (msg._error){
    msg.payload._error = msg._error;
}

return msg;

msg.sequences = flow.get("bridge.image.protocols").filter(protocol => protocol.topic[0] === "error" || protocol.topic[0] === "state").map(dataPoint => {
    return {
        dataPoint: dataPoint
    };
});

if (msg.sequences.length > 0) {
    node.send(msg);
}

node.done();

const alarmMessage = msg.payload;
const name = alarmMessage.name;
const status = alarmMessage.status;
const action = alarmMessage.action;
const sequences = Object.assign(msg.sequences);
var sendMessage = false;

if (action === "Disabled") {
    msg = sequences.find(x => x.dataPoint.id === "ALARM_DISABLED");
    // no message
} else if (action === "Log only") {
    msg = sequences.find(x => x.dataPoint.id === "ALARM_LOG");
    // no message
} else if (action === "Normal") {
    msg = sequences.find(x => x.dataPoint.id === "ALARM_NORMAL");
    sendMessage = true;
} else {
    // Critical
    msg = sequences.find(x => x.dataPoint.id === "ALARM_CRITICAL");
    sendMessage = true;
}

if(sendMessage){
    // Set alarm state
    msg.payload = {};
    msg.payload[msg.dataPoint.id] = status.toLowerCase() === "aktiv" || status.toLowerCase() === "active" ? true : false;
    node.send(msg);

    // Set alarm message
    msg = sequences.find(x => x.dataPoint.id === "ALARM_MESSAGE");
    msg.payload = {};
    msg.payload[msg.dataPoint.id] = status.toLowerCase() === "aktiv" || status.toLowerCase() === "active" ? name : name;
    node.send(msg);

    // Set notification message
    msg = sequences.find(x => x.dataPoint.id === "ALARM_NOTIFICATION_MESSAGE");
    msg.payload = {};
    msg.payload[msg.dataPoint.id] = status.toLowerCase() === "aktiv" || status.toLowerCase() === "active" ? name : "";
    node.send(msg);
}

node.done()

var cloudBridge = global.get("cloud.bridges").find(bridge => {
    return bridge.id === flow.get("bridge").id
})

flow.get("bridge").image.metrics["ALARM_CRITICAL"] = false;
flow.get("bridge").image.metrics["ALARM_NORMAL"] = false;
flow.get("bridge").image.metrics["ALARM_MESSAGE"] = "";
flow.get("bridge").image.metrics["ALARM_NOTIFICATION_MESSAGE"] = "";

cloudBridge.image.metrics = flow.get("bridge").image.metrics;

return msg;

var cloudBridge = global.get("cloud.bridges").find(bridge => {
    return bridge.id === flow.get("bridge").id
})

flow.get("bridge").image.metrics = msg.payload;

if (flow.get("bridge").image.metrics["ALARM_NOTIFICATION_MESSAGE"] === undefined || flow.get("bridge").image.metrics["ALARM_NOTIFICATION_MESSAGE"] === null){
    flow.get("bridge").image.metrics["ALARM_NOTIFICATION_MESSAGE"] = "";
}

cloudBridge.image.metrics = flow.get("bridge").image.metrics;

return msg;

const controllerParameter = flow.get("bridge.image.controller");
const protocols = flow.get("bridge.image.protocols");
var channel = global.get("hardware.interface.serial.channels").concat(global.get("hardware.interface.tcp.channels")).find(channel => channel.id === controllerParameter.channel);

if (channel && controllerParameter && protocols) {
    if (channel.connectorType == "TCP") {
        msg.payload = {
            "connectorType": controllerParameter.connectorType ? controllerParameter.connectorType : channel.connectorType,
            "tcpHost": controllerParameter.tcpHost,
            "tcpPort": controllerParameter.tcpPort,
            "tcpType": controllerParameter.tcpType ? controllerParameter.tcpType : "DEFAULT",
            "unitId": controllerParameter.unitId ? controllerParameter.unitId : 1,
            "commandDelay": controllerParameter.commandDelay ? controllerParameter.commandDelay : 5,
            "clientTimeout": controllerParameter.clientTimeout ? controllerParameter.clientTimeout : 1000,
            "reconnectTimeout": controllerParameter.reconnectTimeout ? controllerParameter.reconnectTimeout : 2000
        };
    } else {
        msg.payload = {
            "connectorType": controllerParameter.connectorType ? controllerParameter.connectorType : channel.connectorType,
            "serialPort": controllerParameter.serialPort ? controllerParameter.serialPort : channel.serialPort,
            "serialBaudrate": controllerParameter.serialBaudrate ? controllerParameter.serialBaudrate : 19200,
            "serialDatabits": controllerParameter.serialDatabits ? controllerParameter.serialDatabits : 8,
            "serialStopbits": controllerParameter.serialStopbits ? controllerParameter.serialStopbits : 1,
            "serialParity": controllerParameter.serialParity ? controllerParameter.serialParity : "none",
            "serialType": controllerParameter.serialType ? controllerParameter.serialType : "RTU-BUFFERD",
            "serialConnectionDelay": controllerParameter.serialConnectionDelay ? controllerParameter.serialConnectionDelay : 100,
            "unitId": controllerParameter.unitId ? controllerParameter.unitId : 1,
            "commandDelay": controllerParameter.commandDelay ? controllerParameter.commandDelay : 5,
            "clientTimeout": controllerParameter.clientTimeout ? controllerParameter.clientTimeout : 1000,
            "reconnectTimeout": controllerParameter.reconnectTimeout ? controllerParameter.reconnectTimeout : 2000
        };
    }
    node.send(msg);
} else {
    node.warn("Invalid channel configuration!");
}

node.done()

msg.svb5_url  = 'http://'+ env.get("REMOTE_MANAGER_HOST") + '/html/xml.cgi' ;
msg.svb5_user = env.get("REMOTE_MANAGER_USER");
msg.svb5_pass = env.get("REMOTE_MANAGER_PW");
msg.svb5_ts   = new Date().toISOString();
node.status({ fill: 'blue', shape: 'ring', text: 'Discovery...' });
return msg;

const user = msg.svb5_user;
const pass = msg.svb5_pass;

const xml = `<cmd user="${user}" password="${pass}" action="read_devices" storeview_only="1" version="C" lang="ger" session_update="no"/>`;

msg.url     = msg.svb5_url;
msg.method  = 'POST';
msg.headers = {
    'Content-Type': 'text/plain',
    'AKSM-auth': 'Basic ' + Buffer.from(user + ':' + pass).toString('base64')
};
msg.payload = 'xml=' + encodeURIComponent(xml);
return msg;

const body = msg.payload;

if (msg.statusCode !== 200) {
    node.error(`HTTP ${msg.statusCode} bei read_devices`);
    return null;
}
const errMatch = body.match(/error="(\d+)"/);
if (errMatch && errMatch[1] !== '0') {
    node.error(`read_devices error=${errMatch[1]}`);
    return null;
}

const deviceRx = /<device\s([^>]+)>([\s\S]*?)<\/device>/g;
const nodes = [];
let m;
while ((m = deviceRx.exec(body)) !== null) {
    const attrs = m[1];
    const inner = m[2];
    const get = k => { const r = attrs.match(new RegExp(k + '="([^"]*)"')); return r ? r[1] : null; };
    const getChild = tag => { const r = inner.match(new RegExp('<' + tag + '>([^<]*)</' + tag + '>')); return r ? r[1].trim() : null; };

    const type = getChild('type');
    const stype = getChild('stype');

    if (type !== 'EVAP' || stype !== '2') continue;

    const bpidx = parseInt(get('bpidx'));
    const nd = parseInt(get('node'));
    const arg1 = parseInt(get('arg1'));
    const arg2 = parseInt(get('arg2'));
    const name = getChild('name');
    const online = get('online') === '1';
    const filex = parseInt(get('filex') || '0');

    if (!bpidx || !nd || !name) continue;

    nodes.push({
        node: nd,
        bpidx, stype: 2, arg1, arg2, name, online, filex,
        disc_value: get('value'),
        disc_status: get('status'),
        disc_alarm: get('alarm') === '1'
    });
}

if (nodes.length === 0) {
    node.error('Keine EVAP-Devices gefunden');
    return null;
}

node.status({ fill: 'blue', shape: 'dot', text: `${nodes.length} Nodes gefunden` });

msg.svb5_nodes = nodes;
msg.svb5_idx = 0;
msg.svb5_results = [];
return msg;

const nd = msg.svb5_nodes[msg.svb5_idx];
const user = msg.svb5_user;
const pass = msg.svb5_pass;

const tableaddress = nd.filex === 4 ? 20017 : 20018;

const xml = `<cmd tableaddress="${tableaddress}" table_name="" user="${user}" password="${pass}" action="read_list" old_cfgtype="0" lang="ger" useparent="0" isconfigure="0" bpidx="${nd.bpidx}" stype="${nd.stype}" nodetype="16" node="${nd.node}" group="0" subgroup="0" page="0" combo="5" index="0" configuretype="0" arg1="${nd.arg1}" arg2="${nd.arg2}" arg3="1" storeview_only="1" version="C" session_update="no"/>`;

msg.url = msg.svb5_url;
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'text/plain',
    'AKSM-auth': 'Basic ' + Buffer.from(user + ':' + pass).toString('base64')
};
msg.payload = 'xml=' + encodeURIComponent(xml);
msg.current_node = nd;

node.status({ fill: 'blue', shape: 'dot', text: `${nd.name} (${msg.svb5_idx + 1}/${msg.svb5_nodes.length})` });
return msg;

const body = msg.payload;
const nd = msg.current_node;

if (msg.statusCode !== 200) {
    node.warn(`HTTP ${msg.statusCode} für ${nd.name}`);
} else {
    const errMatch = body.match(/error="(\d+)"/);
    if (errMatch && errMatch[1] !== '0') {
        node.warn(`SVB5 error ${errMatch[1]} für ${nd.name}`);
    } else {
        let raw;

        if (nd.filex === 4) {
            // ── AK-CC 250: Istwerte aus Discovery ────────────────────
            raw = {
                node: nd.node,
                bpidx: nd.bpidx,
                name: nd.name,
                online: nd.online,
                timestamp: msg.svb5_ts,
                status: nd.disc_status || null,
                alarm: nd.disc_alarm,
                u17: nd.disc_value ? parseFloat(nd.disc_value) : null,
            };
        } else {
            // ── EKC 201 / EKC 2xx/3xx: Items aus read_list ───────────
            const items = {};
            const rx = /<l\s([^>]+?)(?:\s*\/>|\s*>)/g;
            let m;
            while ((m = rx.exec(body)) !== null) {
                const a = m[1];
                const get = k => { const r = a.match(new RegExp(k + '="([^"]*)"')); return r ? r[1] : null; };
                const rawName = get('name');
                if (!rawName) continue;
                const name = rawName.trim().replace(/^\*+/, '');
                const fVal = get('fVal');
                const val = get('value');
                const iVal = get('iVal');
                items[name] = {
                    fVal: fVal !== null ? parseFloat(fVal) : null,
                    value: val ? val.trim() : null,
                    iVal: iVal
                };
            }

            const find = prefix => {
                const key = Object.keys(items).find(k => k.startsWith(prefix));
                return key ? items[key] : null;
            };

            const u00Item = find('u00');
            const ekcItem = find('--- EKC');
            const statusItem = u00Item ?? ekcItem;
            const alarmItem = find('--- Sum alarm');

            raw = {
                node: nd.node,
                bpidx: nd.bpidx,
                name: nd.name,
                online: nd.online,
                timestamp: msg.svb5_ts,
                status: statusItem ? statusItem.value : null,
                status_ival: statusItem ? parseInt(statusItem.iVal) : null,
                alarm: alarmItem ? alarmItem.iVal === '1' : null,
                u17: find('u17') ? find('u17').fVal : null,
                u12: find('u12') ? find('u12').fVal : null,
                u16: find('u16') ? find('u16').fVal : null,
                u09: find('u09') ? find('u09').fVal : null,
                u20: find('u20') ? find('u20').fVal : null,
                u26: find('u26') ? find('u26').fVal : null,
                u23: find('u23') ? find('u23').fVal : null,
                u72: find('U72') ? find('U72').fVal : null,
            };
        }

        const result = Object.fromEntries(Object.entries(raw).filter(([, v]) => v !== null));
        msg.svb5_results.push(result);
    }
}

// Nächster Node?
msg.svb5_idx++;
if (msg.svb5_idx < msg.svb5_nodes.length) {
    return [msg, null, null];
}

// ─── Alle Nodes fertig ────────────────────────────────────────
const r = msg.svb5_results;

const summary = r.map(x =>
    `[node=${x.node}] ${x.name}\n` +
    `  Status  : ${x.status ?? 'n/a'}\n` +
    `  u17     : ${x.u17 !== undefined ? x.u17 + ' °C' : 'n/a'}\n` +
    `  u12     : ${x.u12 !== undefined ? x.u12 + ' °C' : 'n/a'}\n` +
    `  u09     : ${x.u09 !== undefined ? x.u09 + ' °C' : 'n/a'}\n` +
    `  Alarm   : ${x.alarm !== undefined ? (x.alarm ? '⚠ ALARM' : 'OK') : 'n/a'}`
).join('\n\n');

node.status({ fill: 'green', shape: 'dot', text: `${r.length} Nodes gelesen — ${new Date().toLocaleTimeString()}` });

msg.payload = {
    timestamp: msg.svb5_ts,
    count: r.length,
    results: r,
    summary: summary
};

return [null, msg, null];

const results = msg.payload.results;

const flat = results.reduce((acc, x) => {
    const prefix = `node_${x.node}_`;
    Object.entries(x).forEach(([k, v]) => {
        acc[prefix + k] = v;
    });
    return acc;
}, {});

msg.payload = flat;
return msg;

const flat = msg.payload;

const topicMap = {
    alarm      : ['error',     'bool'  ],
    status     : ['state',     'string'],
    status_ival: ['state',     'number'],
    online     : ['state',     'bool'  ],
};
const tempKeys = ['u17','u12','u16','u09','u20','u26','u23','u72'];
const skipKeys = ['node','bpidx','name','timestamp'];

const protocols = Object.entries(flat)
    .filter(([key]) => {
        const prop = key.split('_').slice(2).join('_');
        return !skipKeys.includes(prop);
    })
    .map(([key, value]) => {
        const nodeNr = parseInt(key.split('_')[1]);
        const prop   = key.split('_').slice(2).join('_');

        let topic;
        if (topicMap[prop]) {
            topic = topicMap[prop];
        } else if (tempKeys.includes(prop)) {
            topic = ['telemetry', 'number'];
        } else {
            topic = ['state', typeof value === 'number' ? 'number' : 'string'];
        }

        return {
            id       : key,
            address  : nodeNr,
            type     : typeof value === 'boolean' ? 'bool'
                     : typeof value === 'number'  ? 'float'
                     : 'string',
            fc       : 3,
            offsetbit: 0,
            scale    : 1,
            mask     : "",
            topic
        };
    });

msg.payload = { protocols };
return msg;

const flat = msg.payload;
const results = msg.svb5_results; // brauchen den name pro node

const skipKeys = ['node', 'bpidx', 'name', 'timestamp'];

const propMeta = {
    alarm      : { de: 'Alarm',                    unit: '',   render: [{measurement: true,  de: 'Alarm'}, {measurement: false, de: 'OK'}] },
    status     : { de: 'Betriebsstatus',            unit: '',   render: [{measurement: '',    de: '-'   }] },
    status_ival: { de: 'Betriebsstatus (Code)',     unit: '',   render: [{measurement: '',    de: '-'   }] },
    online     : { de: 'Online',                    unit: '',   render: [{measurement: true,  de: 'Online'}, {measurement: false, de: 'Offline'}] },
    u17        : { de: 'Thermostattemperatur Luft', unit: '°C', render: null },
    u12        : { de: 'S3 Lufttemperatur',         unit: '°C', render: null },
    u16        : { de: 'S4 Lufttemperatur',         unit: '°C', render: null },
    u09        : { de: 'S5 Temperatur',             unit: '°C', render: null },
    u20        : { de: 'S2 Temperatur',             unit: '°C', render: null },
    u26        : { de: 'Verdampfungstemperatur',    unit: '°C', render: null },
    u23        : { de: 'EEV Öffnungsgrad',          unit: '%',  render: null },
    u72        : { de: 'Food Temperatur',           unit: '°C', render: null },
};

const topicMap = {
    alarm      : ['error',    'bool'  ],
    status     : ['state',    'string'],
    status_ival: ['state',    'number'],
    online     : ['state',    'bool'  ],
};
const tempKeys = ['u17','u12','u16','u09','u20','u26','u23','u72'];

// Node-Name lookup: node_71_u17 → name von node 71
const nameByNode = {};
results.forEach(r => { nameByNode[r.node] = r.name; });

const metricSources = Object.entries(flat)
    .filter(([key]) => {
        const prop = key.split('_').slice(2).join('_');
        return !skipKeys.includes(prop);
    })
    .map(([key]) => {
        const nodeNr  = parseInt(key.split('_')[1]);
        const prop    = key.split('_').slice(2).join('_');
        const meta    = propMeta[prop];
        const ndName  = nameByNode[nodeNr] || `Node ${nodeNr}`;

        const topic = topicMap[prop]
            ? topicMap[prop]
            : tempKeys.includes(prop)
                ? ['telemetry', 'number']
                : ['state', 'string'];

        const entry = {
            metricId    : key,
            topic,
            unit        : meta ? meta.unit : '',
            translations: { de: `${ndName} — ${meta ? meta.de : prop}` },
        };

        if (meta && meta.render) {
            entry.render = meta.render.map(r => ({
                measurement: r.measurement,
                translations: { de: r.de }
            }));
        }

        if (topic[1] === 'number') {
            entry.min = 0;
            entry.max = topic[0] === 'telemetry' ? 100 : 9999;
        }

        return entry;
    });

msg.payload = { metricSources };
return msg;

var cloudBridge = global.get("cloud.bridges").find(bridge => {
    return bridge.id === flow.get("bridge").id
})

msg.stateUpstreamRequired = false;
msg.errorUpstreamRequired = false;
for (var propertyName in msg.payload) {
    if (typeof msg.payload[propertyName] === "number") {
        // Round to 2 decimal
        msg.payload[propertyName] = Math.round((msg.payload[propertyName] + Number.EPSILON) * 100) / 100
    }
    flow.get("bridge").image.metrics[propertyName] = msg.payload[propertyName];
}

cloudBridge.image.metrics = flow.get("bridge").image.metrics;

return msg;

msg.payload = {
    "response": msg.payload
}
return msg;
